   357|async function withOwnerDeveloperPg<T>(callback: (client: PgClient) => Promise<T>): Promise<T> {
   358|  const pgModule = await import('pg') as { Pool: PgPoolConstructor };
   359|  const pool = new pgModule.Pool({ connectionString: buildOwnerDeveloperConnectionString(), ssl: { rejectUnauthorized: false }, application_name: 'ivx_owner_developer_tools', max: 1, idleTimeoutMillis: 5_000, connectionTimeoutMillis: 8_000 });
   360|  const client = await pool.connect();
   361|  try {
   362|    return await callback(client);
   363|  } finally {
   364|    client.release();
   365|    await pool.end().catch(() => undefined);
   366|  }
   367|}
