   369|function getBackendServiceRoleKey(): string {
   370|  const anonKey = readBackendEnv('EXPO_PUBLIC_SUPABASE_ANON_KEY');
   371|  const serviceKey = readBackendEnv('SUPABASE_SERVICE_ROLE_KEY') || readBackendEnv('SUPABASE_SERVICE_KEY');
   372|  const role = decodeSupabaseJwtRole(serviceKey);
   373|  if (!serviceKey || serviceKey === anonKey || (role !== 'service_role' && role !== 'supabase_admin')) {
   374|    throw new Error('Backend-only Supabase service-role key is not configured.');
   375|  }
   376|  return serviceKey;
